```c
#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int n, k, x;
    scanf("%d %d %d", &n, &k, &x);
    int *a = malloc(n * sizeof(int));
    for (int i = 0; i < n; i++) {
        scanf("%d", &a[i]);
    }
    qsort(a, n, sizeof(int), compare);
    int result = k * x;
    for (int i = 0; i < n - k; i++) {
        result += a[i];
    }
    printf("%d\n", result);
    free(a);
    return 0;
}
